class Solution(object):
    def pruneTree(self, root):
        def dfs(node):
            if not node:
                return True
            left_empty = dfs(node.left)
            right_empty = dfs(node.right)
            if left_empty:
                node.left = None
            if right_empty:
                node.right = None
            return node.val == 0 and left_empty and right_empty
        dfs(root)
        return root
